<?php
namespace App\Services; use DB;
class TradingEngine{public function run():array{$broker=Factories::broker();$m=Factories::market();$ai=Factories::ai();$risk=new RiskManager();$rows=DB::pdo()->query('SELECT w.*,s.ai_required FROM watchlist w LEFT JOIN strategies s ON s.id=w.strategy_id WHERE w.enabled=1')->fetchAll();$out=[];foreach($rows as $w){$q=$m->quote($w['symbol']);$input=$q+['candles'=>$m->candles($w['symbol']),'position'=>null];$d=$ai->decide($input);DB::pdo()->prepare('INSERT INTO ai_decisions(symbol,decision,confidence,reasoning,input_json) VALUES(?,?,?,?,?)')->execute([$w['symbol'],$d['decision'],$d['confidence'],$d['reasoning'],json_encode($input)]);if($d['decision']==='BUY' && $d['confidence']>=setting('ai.confidence_threshold',70)){[$ok,$why]=$risk->approve(['symbol'=>$w['symbol'],'notional'=>$w['position_size']]); if($ok)$broker->placeOrder(['symbol'=>$w['symbol'],'side'=>'buy','type'=>'market','qty'=>round($w['position_size']/$q['price'],6),'price'=>$q['price']]); $out[]=[$w['symbol'],$d['decision'],$why];}else $out[]=[$w['symbol'],$d['decision'],'No order'];}return $out;}}
